  ('real-estate-moex-00550', 'real-estate', 'real-estate-moex-109-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依消費者保護法所提之訴訟，因企業經營者之故意所致之損害，消費者得請求損害額幾倍以下之 懲罰性賠償金？', '["一倍", "三倍", "五倍", "十倍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "eee13774a356", "answer_pdf_sha1": "04b21f514568", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
